+                    canonicalize_json(&mut v);
+                    new_map.insert(k, v);
+                }
+            }
+            *map = new_map;
+        }
+        serde_json::Value::Array(arr) => {
+            for v in arr {
+                canonicalize_json(v);
+            }
+        }
+        _ => {}
+    }
